1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.10;
3	
4	const BASE_PRICE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	function itemPremium(items: { type: string }[]): number {
12	  if (items.length === 0) return 0;
13	  const base = BASE_PRICE[items[0].type];
14	  return base + base * FIRST_INSURANCE_RATE;
15	}
16	
17	export function quote(
18	  policy: { customer: { years: number }; items: { type: string }[] },
19	  _options: { isFollowUp: boolean }
20	): { premium: number } {
21	  return { premium: itemPremium(policy.items) + PROCESSING_FEE };
22	}
